import { useRef, useState, useEffect } from "react";

export const Player = ({ fn, song, onBack }) => {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [current, setCurrent] = useState(0);
  const [duration, setDuration] = useState(30);
  const [ready, setReady] = useState(false); // ← key fix: wait for audio to be ready

  // When song changes, reset everything
  useEffect(() => {
    setPlaying(false);
    setProgress(0);
    setCurrent(0);
    setReady(false);
  }, [song]);

  const handleCanPlay = () => {
    setReady(true); // audio is loaded and safe to play
  };

  // ✅ THE FIX: always await play() and catch the AbortError
  // The error happens when play() is called before the browser is ready
  const togglePlay = async () => {
    const audio = audioRef.current;
    if (!audio || !ready) return;

    if (playing) {
      audio.pause();
      setPlaying(false);
    } else {
      try {
        await audio.play(); // await prevents the race condition
        setPlaying(true);
      } catch (err) {
        // AbortError = browser interrupted it (safe to ignore)
        // NotAllowedError = browser blocked autoplay
        if (err.name !== "AbortError") {
          console.error("Playback error:", err.message);
        }
      }
    }
  };

  const handleTimeUpdate = () => {
    const audio = audioRef.current;
    if (!audio) return;
    const dur = audio.duration || 30;
    setCurrent(audio.currentTime);
    setProgress((audio.currentTime / dur) * 100);
  };

  const handleSeek = (e) => {
    const audio = audioRef.current;
    if (!audio) return;
    const pct = e.target.value;
    audio.currentTime = (pct / 100) * (audio.duration || 30);
    setProgress(pct);
  };

  const handleEnded = () => {
    setPlaying(false);
    setProgress(0);
    setCurrent(0);
  };

  const fmt = (s) =>
    `${Math.floor(s / 60)}:${String(Math.floor(s % 60)).padStart(2, "0")}`;

  // Support both: called from SearchPage (fn prop) or PlayerPage (onBack prop)
  const handleBack = () => {
    if (audioRef.current) audioRef.current.pause();
    if (onBack) onBack();
    else if (fn) fn(false, null);
  };

  return (
    <div className="player-container">
      <button className="back-btn" onClick={handleBack}>
        ← Back to Songs
      </button>

      <div className="player-card">
        <img
          src={song.artworkUrl600 || song.artworkUrl100}
          alt={`${song.trackName} by ${song.artistName}`}
          className="player-artwork"
        />

        <div className="player-info">
          <h2 className="player-track">{song.trackName}</h2>
          <p className="player-artist">{song.artistName}</p>
          <p className="player-genre">{song.primaryGenreName}</p>
        </div>

        <div className="player-controls">
          {/* Progress bar */}
          <div className="progress-wrap">
            <span className="time-label">{fmt(current)}</span>
            <input
              type="range"
              min="0"
              max="100"
              value={progress}
              onChange={handleSeek}
              className="progress-bar"
              disabled={!ready}
            />
            <span className="time-label">{fmt(duration)}</span>
          </div>

          {/* Play / Pause button */}
          <button
            className={`play-btn ${!ready ? "disabled" : ""}`}
            onClick={togglePlay}
            disabled={!ready}
          >
            {!ready ? "Loading..." : playing ? "⏸ Pause" : "▶ Play"}
          </button>

          {/* Preview notice */}
          <p className="preview-note">🎵 30-second iTunes preview</p>
        </div>
      </div>

      {/* Hidden audio element — we control it via ref */}
      <audio
        ref={audioRef}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={(e) => setDuration(e.target.duration)}
        onCanPlay={handleCanPlay} // ← fires when browser is ready to play
        onEnded={handleEnded}
        preload="auto" // ← tells browser to load audio immediately
      >
        <source src={song.previewUrl} type="audio/mp4" />
        Your browser does not support the audio element.
      </audio>
    </div>
  );
};
